  and m.module_number = 5 and l.lesson_number = 1;

update public.lessons l set enhancements = $ench${"industryStory":"AI generated 40 test cases — but they were unprioritised and some overlapped. A tester pruned duplicates and ranked the rest by risk, turning a noisy list into a focused, runnable set. Generation is easy; prioritisation is the skill.","davidTip":"More cases is not better testing. Use AI to generate broadly, then cut duplicates and prioritise by risk so the most important checks run first. A tidy, risk-ranked set beats a long unranked one.","miniChallenge":"Take an AI-generated set of cases and reduce it: merge duplicates and tag each remaining case high/medium/low risk.","modelAnswer":"## Example\nFrom 18 generated cases I merged 4 near-duplicates, dropped 2 irrelevant ones, and tagged the payment and lockout cases High, validation messages Medium, and cosmetic checks Low — a focused set of 12."}$ench$::jsonb
