update public.lessons l set enhancements = $ench${"industryStory":"A generated case asserted a \"loyalty points\" message the feature never showed — a hallucination. Another set missed every boundary case. The value was entirely in the tester's review, which caught both.","badGood":{"label":"AI-generated test cases","bad":"Accept all 20 generated cases as-is and run them.","good":"Review them: remove the hallucinated \"loyalty points\" case, add the missing 8–20 char password boundaries, tighten vague expected results — then run."},"davidTip":"Review AI-generated tests like work from a junior: check expected results are specific and correct, remove anything invented, and add the boundary/negative cases it missed. Your review is the value-add.","miniChallenge":"Generate test cases for a feature, then list two issues you found and fixed in review (one missing case, one incorrect/invented).","modelAnswer":"## Example\nIssue 1: a case referenced an \"SMS code\" step the product does not have — removed. Issue 2: no boundary case for the max comment length — added 500 and 501 characters.","resourcePreview":{"name":"AI Test Case Review Checklist","purpose":"A checklist for turning an AI draft into a strong, trustworthy test set.","whenToUse":"Run every AI-generated set through it before use.","formats":["PDF","DOCX"]}}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
