update public.lessons l set enhancements = $ench${"industryStory":"A tester needed realistic-but-fake data for 50 test users and was hand-typing names and emails. AI generated valid, varied synthetic data in seconds — no real customer data involved — and testing sped up dramatically.","davidTip":"AI is excellent for synthetic test data — varied names, emails, edge-case values — but never ask it to use real customer data, and check generated data is actually valid for your field rules.","miniChallenge":"Prompt AI for 10 rows of synthetic test data for a sign-up form (including a couple of edge cases), and check each row is valid for the rules.","modelAnswer":"## Example\nAI produced 10 users with valid emails and 8–20 char passwords, plus edge cases: a name with an apostrophe, a very long email, and a minimum-length password — all synthetic, all valid to test with."}$ench$::jsonb
