update public.lessons l set enhancements = $ench${"davidTip":"For this assignment, the review is what proves QA skill — show what you accepted, changed and rejected from the AI output, not just the generated cases.","miniChallenge":"Before submitting, attach a short review note to your generated set: what you kept, what you fixed, and why.","managersReview":{"intro":"If I reviewed this AI test-design assignment as a QA lead, I would look for:","strengths":["Generated cases hardened by review","Boundary/negative coverage added","Hallucinations removed; risk-prioritised"],"gaps":["Generated cases shipped unreviewed","Happy-path only","Vague expected results"],"improvements":["Add a review note (kept/changed/rejected)","Apply boundary/equivalence techniques","Tighten expected results"]},"portfolioBuilder":"A \"generated vs reviewed\" test set — with your review notes — is a standout portfolio piece showing both AI use and testing judgement."}$ench$::jsonb
