update public.lessons l set enhancements = $ench${"industryStory":"Scripted tests all passed, yet a tester exploring freely found a broken flow when they refreshed mid-checkout. Exploratory testing — structured, curious investigation — finds what scripts miss. AI can supercharge the idea-generation, but the exploring is human.","visualAid":{"type":"comparison","title":"Scripted vs exploratory testing","headers":["","Scripted","Exploratory"],"rows":[["Approach","Follow predefined steps","Investigate and adapt"],["Finds","Known expected behaviour","Surprises and edge cases"],["AI helps with","Drafting the scripts","Generating charters and ideas"]]},"davidTip":"Exploratory testing is structured curiosity, not random clicking. Time-box it, take notes, and let what you find drive where you look next. AI helps you start with more and better ideas.","miniChallenge":"Pick a feature and write a 45-minute exploratory session plan: a mission and three areas/risks to investigate.","modelAnswer":"## Example — password reset\nMission: probe the reset flow for security and error handling. Areas: expired/used links, requesting resets for unknown emails, and interrupting the flow (refresh, back button)."}$ench$::jsonb
