update public.lessons l set enhancements = $ench${"industryStory":"A tester used AI to mind-map \"ways a file upload could fail\" and got a branching set of ideas — file type, size, name, interruption, permissions — that became a thorough exploratory session. AI is a fast brainstorming partner for scenarios.","davidTip":"Prompt AI with heuristics — boundaries, interruptions, unusual data, hostile users — to widen your scenario ideas. You still decide which doors are worth opening, but you start with far more of them.","miniChallenge":"Ask AI to brainstorm \"ways [a feature] could fail\" using at least three heuristics, then choose the three scenarios most worth exploring.","modelAnswer":"## Example — file upload\nIdeas: huge file, wrong type renamed to .jpg, upload then lose connection, special characters in filename, upload while logged out. Top three: renamed wrong-type file, connection loss mid-upload, logged-out upload."}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
