update public.lessons l set enhancements = $ench${"industryStory":"Drowning in 200 support tickets, a tester pasted (sanitised) summaries into AI and asked for patterns. It clustered them — most were one login issue on one browser — turning noise into a single high-priority defect.","davidTip":"AI is strong at spotting patterns across many items — defects, tickets, logs. Use it to cluster and summarise (with sanitised data), then verify the pattern is real before acting on it.","miniChallenge":"Take a list of 8–10 (made-up or sanitised) issue summaries, ask AI to group them by theme, and identify the most important cluster.","modelAnswer":"## Example\nAI grouped 10 issues into: login failures on Safari (5), slow dashboard (3), cosmetic (2). The Safari login cluster is the priority — likely one root cause affecting the most users."}$ench$::jsonb
