  and m.module_number = 9 and l.lesson_number = 2;

update public.lessons l set enhancements = $ench${"industryStory":"A flaky test failed randomly. The tester pasted it (sanitised) into AI, which spotted a fixed wait and suggested a web-first assertion. They applied it, re-ran, and the flakiness disappeared — verified, not assumed.","davidTip":"AI is excellent at explaining errors and suggesting refactors — pair it with the actual failure detail (trace/log). Always re-run after applying a fix to confirm the behaviour is unchanged; never trust the explanation alone.","miniChallenge":"Take a flaky or failing test (or describe one), ask AI to explain and fix it, and note how you would verify the fix.","modelAnswer":"## Example\nAI identified a waitForTimeout before an assertion and suggested replacing it with expect(locator).toBeVisible(). I applied it and ran the test 10× with --repeat-each to confirm it is now stable."}$ench$::jsonb
