update public.lessons l set enhancements = $ench${"industryStory":"Two testers learned the same AI techniques. One used them ad hoc and forgot half; the other built a repeatable workflow — AI at refinement, test design, data, reporting — and got consistent value every sprint. A workflow turns techniques into habits.","visualAid":{"type":"flow","title":"A repeatable AI-assisted QA workflow","steps":[{"label":"Refinement","detail":"AI finds gaps"},{"label":"Test design","detail":"AI drafts, you review"},{"label":"Data","detail":"synthetic data"},{"label":"Reporting","detail":"AI drafts, you shape"}],"caption":"Verify and own at every step."},"davidTip":"Design a workflow you will actually repeat: where AI helps in each sprint stage, and what you always verify. A consistent, safe workflow beats occasional clever prompts.","miniChallenge":"Sketch your personal AI QA workflow across a sprint: where AI helps and what you verify at each point.","modelAnswer":"## Example\nRefinement: AI surfaces story gaps → I raise questions. Test design: AI drafts cases → I review and add boundaries. Data: AI generates synthetic data. Reporting: AI drafts the summary → I lead with risk. I verify specifics throughout.","resourcePreview":{"name":"AI-Assisted QA Workflow Poster","purpose":"Shows where AI helps across the testing lifecycle and where judgement stays in control.","whenToUse":"Pin it as a reminder of your repeatable workflow.","formats":["PDF","DOCX"]}}$ench$::jsonb
