  and m.module_number = 12 and l.lesson_number = 1;

update public.lessons l set enhancements = $ench${"industryStory":"A tester who saved their best prompts, tools and rules in one place walked into a new role productive on day one — they started each task from a proven toolkit instead of a blank box.","davidTip":"Your AI toolkit — saved prompts, go-to tool per task, personal rules — is a genuine career asset. Build it deliberately and keep it current; it is what makes you fast and consistent.","miniChallenge":"Assemble your toolkit: 3 saved prompts (task + prompt + when to use), your tool-per-task list, and your top personal rule.","modelAnswer":"## Example\nPrompts: test design, requirement review, bug-report polish. Tool-per-task: [approved tool] for drafting, docs for verification. Rule: never paste real customer or production data.","resourcePreview":{"name":"Personal AI Toolkit Planner","purpose":"A template to capture your prompts, tools and personal AI rules.","whenToUse":"Fill it in now and refine it monthly.","formats":["PDF","DOCX"]}}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
