  and m.module_number = 12 and l.lesson_number = 2;

update public.lessons l set enhancements = $ench${"industryStory":"A manager asked \"is AI actually helping us, or just feeling fast?\" The tester who could point to concrete gains — faster test drafting, earlier gap-spotting, fewer escaped defects — made the case; vague enthusiasm would not have.","davidTip":"Be able to show the value, not just claim it: time saved on drafting, gaps caught earlier, coverage improved. Measuring AI's impact (even roughly) is what turns \"I use AI\" into a credible professional story.","miniChallenge":"List three ways you could measure whether AI is genuinely improving your testing, and how you would track each.","modelAnswer":"## Example\n- Time to draft a test set (before vs with AI)\n- Requirement gaps caught at refinement (count per sprint)\n- Escaped defects trend (are we catching more earlier?)\nTrack simply in a note or sheet over a few sprints."}$ench$::jsonb
