  and m.module_number = 12 and l.lesson_number = 3;

update public.lessons l set enhancements = $ench${"davidTip":"For your capstone, present a complete, repeatable, responsible AI QA workflow — prompts, where AI fits, your rules, and how you verify. This is the artefact that shows an employer you use AI like a professional, not a novelty.","miniChallenge":"Assemble your AI QA Pack: your workflow, your toolkit (prompts + rules), one worked example (prompt → output → your review), and your governance statement.","modelAnswer":"## Example contents\n1) Workflow diagram across the sprint. 2) Toolkit: 5 saved prompts + tool-per-task + 4 rules. 3) Worked example: a generated test set with my review notes. 4) Governance statement (data, verification, accountability).","managersReview":{"intro":"If I received your AI QA Pack as a hiring manager, I would look for:","strengths":["A repeatable, sensible workflow","A real toolkit with safe rules","A worked example showing review/judgement","Clear governance"],"gaps":["Generic claims with no examples","No data/safety rules","AI output unreviewed"],"improvements":["Include a real prompt→output→review example","State your governance rules","Show where your judgement shaped the result"]},"portfolioBuilder":"This AI QA Pack is the centrepiece artefact for this course — a modern, credible portfolio piece proving you combine testing fundamentals with responsible, effective AI use."}$ench$::jsonb
